const outputId = String(msg.req && msg.req.params ? (msg.req.params.output_id || '') : '').trim();
const outputsById = global.get('aiInsightOutputsById') || {};

if (!outputId) {
    msg.statusCode = 404;
    msg.headers = { 'Content-Type': 'application/json' };
    msg.payload = { detail: 'Output not found' };
    return [null, msg];
}

const record = outputsById[outputId];
if (!record || typeof record !== 'object') {
    msg.statusCode = 404;
    msg.headers = { 'Content-Type': 'application/json' };
    msg.payload = { detail: 'Output not found' };
    return [null, msg];
}

msg.statusCode = 200;
msg.headers = { 'Content-Type': 'application/json' };
msg.payload = JSON.parse(JSON.stringify(record));
return [msg, null];

if (!msg.res) {
    return null;
}

const alreadySent = !!(msg.res.headersSent || (msg.res._res && (msg.res._res.headersSent || msg.res._res.writableEnded)));
if (alreadySent) {
    return null;
}

msg.statusCode = 500;
msg.headers = { 'Content-Type': 'application/json' };
msg.payload = { detail: 'internal_error' };
return msg;
